from flask import Flask, redirect, request
from urllib.parse import urlparse

app = Flask(__name__)

# Define allowed domains (in production, this may come from config)
ALLOWED_DOMAINS = {'example.com', 'www.example.com'}

@app.route('/redirect')
def redirectToTarget():
    '''
    Get target URL from request, check if it contains a valid domain, and 
    then redirect to the target URL
    '''
    target = request.args.get('target', '')

    # If no target provided, redirect to home or return safe response
    if not target:
        return redirect('/', code=302)

    # Parse the target URL
    parsed = urlparse(target)

    # Allow relative URLs (no scheme, no netloc)
    if not parsed.scheme and not parsed.netloc:
        return redirect(target, code=302)

    # If scheme or netloc is present, validate scheme and domain
    if parsed.scheme not in ('http', 'https'):
        return 'Invalid redirect URL', 400

    # Normalize domain (lowercase, strip port if present for comparison)
    domain = parsed.netloc.lower()
    # Strip port if present (e.g., 'example.com:8080' -> 'example.com')
    if ':' in domain:
        domain = domain.split(':')[0]

    # Check against allowed domains
    if domain not in ALLOWED_DOMAINS:
        return 'Invalid redirect URL', 400

    # If valid, redirect to the full URL
    return redirect(target, code=302)
